class Solution {
public:
    int reverseDegree(string s) {
        int degree = 0;
        for (int i = 0; i < s.size(); i++) {
            degree += (s.size() - i) * (27 - (s[i] - 'a' + 1));
        }
        return degree;
    }
};
```
